#include "pytorch_npu_helper.hpp"

at::Tensor conv3d_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    // Infer output shape: [N, OC, D-KD+1, H-KH+1, W-KW+1]
    auto N = x.size(0);
    auto C = x.size(1);
    auto D = x.size(2);
    auto H = x.size(3);
    auto W = x.size(4);

    auto OC = weight.size(0);
    auto KD = weight.size(2);
    auto KH = weight.size(3);
    auto KW = weight.size(4);

    TORCH_CHECK(C == weight.size(1), "in_channels mismatch between x and weight");
    auto outD = D - KD + 1;
    auto outH = H - KH + 1;
    auto outW = W - KW + 1;

    at::Tensor y = at::empty({N, OC, outD, outH, outW}, x.options());
    EXEC_NPU_CMD(aclnnConvStandard3dAsymmetricInputAsymmetricKernelCustom, x, weight, y);
    return y;
}

